mapper.select:
select distinct spec_code from T_LH_SCHEDULE_RESULT
where FACTORY_CODE = #{factoryCode}

    AND DATE_FORMAT(schedule_date, '%Y-%m-%d' ) >= #{beginDate}


    AND DATE_FORMAT(schedule_date, '%Y-%m-%d' ) < #{endDate}


    AND spec_code IN

        #{item}


AND IS_DELETE = '0'

SELECT MAX(schedule_date)
FROM t_lh_schedule_result
WHERE factory_code = #{factoryCode}

    AND schedule_date < #{lastScheduleTime}

SELECT batch_no
FROM t_lh_schedule_result
WHERE schedule_date = #{scheduleDate}
  AND factory_code = #{factoryCode}
  AND is_delete = 0
GROUP BY batch_no

mapper.delete:
DELETE FROM t_lh_schedule_result
WHERE FACTORY_CODE = #{factoryCode}
  AND SCHEDULE_DATE = #{scheduleDate}

mapper.select:
select count(1)
from t_schedule_publish_record
where procedure_code = #{procedureCode,jdbcType=VARCHAR}
  and schedule_date = #{scheduleDate,jdbcType=DATE}
  and publish_status = '1'
  and del_flag = '0'

mapper.update:
update t_lh_schedule_result set IS_RELEASE = #{status}
, PUBLISH_SUCCESS_COUNT = PUBLISH_SUCCESS_COUNT + 1, NEWEST_PUBLISH_TIME = now()
where id in

    #{id}

UPDATE t_schedule_publish_record
SET PUBLISH_STATUS = #{status}
WHERE data_version = #{dataVersion}
